const input = $json.body || $json;

const value = input.entry?.[0]?.changes?.[0]?.value || {};
const msg = value.messages?.[0] || {};
const contact = value.contacts?.[0] || {};
const metadata = value.metadata || {};

const content =
  msg.button?.text ||
  msg.button?.payload ||
  msg.interactive?.button_reply?.title ||
  msg.interactive?.button_reply?.id ||
  msg.text?.body ||
  '';

const contentLower = String(content).trim().toLowerCase();

const inboxPorNumero = {
  "551152360228": 29,
  "551151980357": 21
};

const inbox_id_desejado =
  inboxPorNumero[metadata.display_phone_number] ?? null;

const botoesOptout = [
  'Bloquear contato / Sem interesse',
  'Não receber',
  'Sem interesse',
  'Bloquear contato'
];

const botoesOptin = [
  'Ver detalhes',
  'Conversar no WhatsApp',
  'Confirmar',
  'Responder',
  'Conversar',
  'Receber Análise',
  'Ver diagnóstico',
  'Conversar com a empresa',
  'Conversar com a equipe',
  'Confirmar recebimento',
  'Não quero responder desta vez'
];

const normalizar = texto =>
  String(texto || '').trim().toLowerCase();

const botoesOptoutLower = botoesOptout.map(normalizar);
const botoesOptinLower = botoesOptin.map(normalizar);

const isRespostaBotao =
  msg.type === 'button' &&
  [...botoesOptoutLower, ...botoesOptinLower].includes(contentLower);

let botaoAcao = null;

if (isRespostaBotao && botoesOptoutLower.includes(contentLower)) {
  botaoAcao = 'optout';
}

if (isRespostaBotao && botoesOptinLower.includes(contentLower)) {
  botaoAcao = 'optin';
}

return [{
  json: {
    // Dados da mensagem
    // message_id: msg.id,
    message_type: msg.type,
    // timestamp: msg.timestamp,

    // Contato
    sender_phone: msg.from,
    // sender_identifier: contact.user_id,
    sender_name: contact.profile?.name || null,

    // Número da empresa
    // phone_number_id: metadata.phone_number_id,
    display_phone_number: metadata.display_phone_number,
    inbox_id_desejado: inbox_id_desejado || 99,

    // Contexto
    reply_to_wamid: msg.context?.id || null,
    is_reply_to_wamid: !!msg.context?.id,

    // Conteúdo
    message_content: content,
    message_content_lower: contentLower,

    // Botões
    is_resposta_botao: isRespostaBotao,
    botao_texto: isRespostaBotao ? content : null,
    botao_texto_lower: isRespostaBotao ? contentLower : null,
    botao_tipo: isRespostaBotao ? 'quick_reply_template' : null,

    botao_acao: botaoAcao,
    is_optin: botaoAcao === 'optin',
    is_optout: botaoAcao === 'optout',

    // Payload bruto do botão
    button: msg.button || null,

    // Payload completo da Meta
    // raw: input
  }
}];

const payload = $input.first().json;

// ======================
// Detecta origem
// ======================

const chatwoot = payload.body?.event;
const meta = payload.body?.entry?.[0]?.changes?.[0]?.value;

let provider = 'unknown';
let msg = null;

if (chatwoot) {
  provider = 'chatwoot';
  msg = payload.body;
}
else if (meta?.messages?.length) {
  provider = 'meta';
  msg = meta.messages[0];
}

// ======================
// Tipo da mensagem
// ======================

let msg_type = 'unknown';

if (!msg) {
  msg_type = 'none';
}

// ---------- CHATWOOT ----------

else if (provider === 'chatwoot') {

  if (msg.private) {
    msg_type = 'private_note';
  } else {
    msg_type = msg.content_type || 'text';
  }

}

// ---------- META ----------

else {

  if (msg.interactive?.nfm_reply) {
    msg_type = 'flow';
  } else if (msg.interactive?.button_reply) {
    msg_type = 'button_reply';
  } else if (msg.interactive?.list_reply) {
    msg_type = 'list_reply';
  } else if (msg.button) {
    msg_type = 'button';
  } else if (msg.text) {
    msg_type = 'text';
  } else if (msg.image) {
    msg_type = 'image';
  } else if (msg.video) {
    msg_type = 'video';
  } else if (msg.audio) {
    msg_type = 'audio';
  } else if (msg.document) {
    msg_type = 'document';
  } else if (msg.sticker) {
    msg_type = 'sticker';
  } else if (msg.location) {
    msg_type = 'location';
  } else if (msg.contacts) {
    msg_type = 'contacts';
  } else if (msg.reaction) {
    msg_type = 'reaction';
  } else if (msg.order) {
    msg_type = 'order';
  } else {
    msg_type = msg.type || 'unknown';
  }

}

// ======================
// Normalização
// ======================

const normalized = {
  provider,

  msg_type,

  type: msg?.type || msg?.content_type,

  text:
    msg?.content ??
    msg?.text?.body ??
    null,

  private:
    provider === 'chatwoot'
      ? !!msg.private
      : false,

  message_id:
    msg?.id,

  conversation_id:
    msg?.conversation?.id ??
    payload.body?.conversation?.id ??
    null,

  from:
    msg?.from ??
    payload.body?.meta?.sender?.phone_number ??
    payload.body?.meta?.sender?.identifier ??
    null,

  image: msg?.image,
  video: msg?.video,
  audio: msg?.audio,
  document: msg?.document,
  sticker: msg?.sticker,
  location: msg?.location,
  contacts: msg?.contacts,
  interactive: msg?.interactive,
  button: msg?.button,

  raw: msg
};

return [{
  json: {
    ...normalized,
    ...payload
  }
}];

