const flowResponse = $json.flow_response || '{}';

let respostas = {};

try {
  respostas = JSON.parse(flowResponse);
} catch (e) {
  return [{
    json: {
      erro: 'flow_response inválido',
      flow_response
    }
  }];
}

function parseOpcao(valor) {
  if (!valor) return null;

  const partes = String(valor).split('_');

  return {
    indice: Number(partes[0]),
    valor: partes
      .slice(1)
      .join(' ')
      .replace(/\s*•\s*/g, ' • ')
      .replace(/\s+/g, ' ')
      .trim()
  };
}

// Nota do NPS
const nota = Number(
  respostas.screen_0_Escolha_sua_nota_de_satisfao_0
    .replace("menos_de_5", "4")
    .split("_")[1]
);

// Classificação
let score = "DETRATOR";

if (nota >= 9) {
  score = "PROMOTOR";
} else if (nota >= 7) {
  score = "NEUTRO";
}

return [{
  json: {
    flow_token: respostas.flow_token,

    nps: {
      nota,
      score,
      bruto: respostas.screen_0_Escolha_sua_nota_de_satisfao_0
    },

    avaliacoes: {
      tempo_resposta: parseOpcao(respostas.screen_2_Tempo_de_resposta_0),
      clareza_estrategica: parseOpcao(respostas.screen_2_Clareza_estratgica_1),
      qualidade_leads: parseOpcao(respostas.screen_2_Qualidade_dos_leads_2),
      seguranca_gestao: parseOpcao(respostas.screen_2_Segurana_na_gesto_3)
    },

    comentario: respostas.screen_1_Deixe_um_comentrio_0 || null,

    respostas,
    raw: flowResponse
  }
}];

